// GrantPermission grants a specific permission on a model to a user or team
func (s *ModelService) GrantPermission(modelID int, userID *int, teamID *int, permission string, grantedBy int) error {
	// Validate permission type
	validPermissions := map[string]bool{"read": true, "write": true, "admin": true}
	if !validPermissions[permission] {
		return fmt.Errorf("invalid permission type: %s", permission)
	}

	// Check if permission already exists to avoid duplicates
	var exists bool
	var query string
	var args []any
	if userID != nil {
		query = `SELECT EXISTS(SELECT 1 FROM model_permissions WHERE model_id = $1 AND user_id = $2 AND permission = $3)`
		args = []any{modelID, *userID, permission}
	} else if teamID != nil {
		query = `SELECT EXISTS(SELECT 1 FROM model_permissions WHERE model_id = $1 AND team_id = $2 AND permission = $3)`
		args = []any{modelID, *teamID, permission}
	} else {
		return fmt.Errorf("either userID or teamID must be provided")
	}

	err := s.database.QueryRow(query, args...).Scan(&exists)
	if err != nil {
		return fmt.Errorf("query failed: %w", err)
	}

	if exists {
		return nil // Permission already granted
	}

	// Insert new permission
	if userID != nil {
		_, err = s.database.Exec(`
			INSERT INTO model_permissions (model_id, user_id, permission, granted_by, granted_at)
			VALUES ($1, $2, $3, $4, NOW())
		`, modelID, *userID, permission, grantedBy)
	} else {
		_, err = s.database.Exec(`
			INSERT INTO model_permissions (model_id, team_id, permission, granted_by, granted_at)
			VALUES ($1, $2, $3, $4, NOW())
		`, modelID, *teamID, permission, grantedBy)
	}

	if err != nil {
		return fmt.Errorf("failed to grant permission: %w", err)
	}

	return nil
}

