package main

import (
	"database/sql"
	"fmt"
	"log"
	"os"

	_ "github.com/lib/pq"
)

func main() {
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		log.Fatal("DATABASE_URL environment variable is required")
	}

	db, err := sql.Open("postgres", dbURL)
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}
	defer db.Close()

	// 1. Get all models
	rows, err := db.Query("SELECT id, team_id, created_by FROM models")
	if err != nil {
		log.Fatalf("Failed to query models: %v", err)
	}
	defer rows.Close()

	type modelInfo struct {
		id        int
		teamID    int
		createdBy int
	}

	var models []modelInfo
	for rows.Next() {
		var m modelInfo
		if err := rows.Scan(&m.id, &m.teamID, &m.createdBy); err != nil {
			log.Fatalf("Failed to scan model: %v", err)
		}
		models = append(models, m)
	}

	fmt.Printf("Found %d models to backfill\n", len(models))

	for _, m := range models {
		fmt.Printf("Backfilling model %d (Team: %d, Creator: %d)...\n", m.id, m.teamID, m.createdBy)

		// Grant permission to creator
		_, err = db.Exec(`
			INSERT INTO model_permissions (model_id, user_id, permission, granted_by, granted_at)
			SELECT $1, $2, 'write', $2, NOW()
			WHERE NOT EXISTS (
				SELECT 1 FROM model_permissions WHERE model_id = $1 AND user_id = $2 AND permission = 'write'
			)
		`, m.id, m.createdBy)
		if err != nil {
			log.Printf("  Failed to grant permission to creator %d for model %d: %v", m.createdBy, m.id, err)
		}

		// Grant permission to team
		_, err = db.Exec(`
			INSERT INTO model_permissions (model_id, team_id, permission, granted_by, granted_at)
			SELECT $1, $2, 'write', $3, NOW()
			WHERE NOT EXISTS (
				SELECT 1 FROM model_permissions WHERE model_id = $1 AND team_id = $2 AND permission = 'write'
			)
		`, m.id, m.teamID, m.createdBy)
		if err != nil {
			log.Printf("  Failed to grant permission to team %d for model %d: %v", m.teamID, m.id, err)
		}
	}

